prompt --application/shared_components/reports/report_queries/socio_acredita
begin
wwv_flow_imp_shared.create_shared_query(
 p_id=>wwv_flow_imp.id(63191205951276066)
,p_name=>'Socio_acredita'
,p_static_id=>'SOCIO_ACREDITA'
,p_include_session_state=>'N'
,p_report_layout_id=>wwv_flow_imp.id(63190088141211480)
,p_format=>'PDF'
,p_output_file_name=>'Socio_acredita'
,p_content_disposition=>'ATTACHMENT'
);
wwv_flow_imp_shared.create_shared_query_stmnt(
 p_id=>wwv_flow_imp.id(63191582056276072)
,p_shared_query_id=>wwv_flow_imp.id(63191205951276066)
,p_name=>'Socio_acredita'
,p_display_sequence=>1
,p_data_loop_name=>'acredita'
,p_location=>'LOCAL'
,p_query_type=>'SQL'
,p_sql_statement=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT  S.SOCIO_ID,',
'        S.CEDULA,',
'        S.NROSOCIO,',
'        S.APELLIDOSNOMBRES,',
'        A.SITUACION,',
'        TO_CHAR(FN_NOW_LOCAL(),''HH24:MI:SS'') AS HORA,',
'        TO_CHAR(SYSDATE,''DD-MM-YYYY'') AS FECHA,',
'        COALESCE(sys_context(''APEX$SESSION'',''APP_USER''),USER) AS USUARIO_COD',
'FROM MIVOTO_SOCIO S',
'JOIN MIVOTO_ACREDITACION A',
'    ON A.SOCIO_ID = S.SOCIO_ID',
'WHERE S.CEDULA   = :P21_CEDULA',
'OR    S.NROSOCIO = :P21_NROSOCIO',
''))
);
end;
