' --Show or hide labels on each data points [1,0]',
' ''showDataLabels'' VALUE 0,',
' --Whether to show each point in line [1,0]',
' ''showDataPoints'' VALUE 1,',
' --Cut tick text after num of characters [num]',
' ''xTickCutAfter'' VALUE 30,',
' --Set maximum num of tick texts on a axis [num]',
' ''xTickMaxNumber'' VALUE 15,',
' --Show or hide tooltip [1,0]',
' ''tooltipShow'' VALUE 1,',
' --Set if tooltip is grouped or not for the data points [1,0]',
' ''tooltipGrouped'' VALUE 1,',
' --Label of the x axis',
' ''xLabel'' VALUE ''X Axis'',',
' --show x axis',
' ''xShow'' VALUE 1,',
' --Set type of x axis. avail types are <b>indexed</b> own index is generated, <b>category</b> x values are taken from data set,',
' --<b>timeseries</b> dates are taken from data set <b>x.timeFormat</b> has to be set',
' ''xType'' VALUE ''category'',',
' --Label of the y axis',
' ''yLabel'' VALUE ''Y Axis'',',
' --Set max range the y axis [num]',
' ''yMax'' VALUE NULL,',
' --Set min range the y axis [num]',
' ''yMin'' VALUE NULL,',
' --y unit',
' ''yUnit'' VALUE NULL,',
' -- max number of ticks for y axis',
' ''yTickMaxNumber'' VALUE NULL,',
' --Label of the y2 axis',
' ''y2Label'' VALUE ''Y2 Axis'',',
' --Set max range the y2 axis [num]',
' ''y2Max'' VALUE NULL,',
' --Set min range the y2 axis [num]',
' ''y2Min'' VALUE NULL,',
' --max num of ticks for y2 axis',
' ''y2TickMaxNumber'' VALUE NULL,',
' --Enable or disable zoom [1,0]',
' ''zoomEnabled'' VALUE 1,',
' --Set zoomtype. Available types are scroll, subchart, drag',
' ''zoomType'' VALUE ''drag'',',
' --Rescale y axis on zoom',
' ''zoomRescale'' VALUE 0 RETURNING BLOB),',
'''itemData'' VALUE (SELECT JSON_ARRAYAGG(JSON_OBJECT(',
' --ID that references the series [alphanum]',
' ''seriesID'' VALUE ''Series '' || SERIES_ID,',
' --ID that references the group [alphanum]',
' ''groupID'' VALUE 1,',
' --label of the series [string]',
' ''label'' VALUE ''Series '' || SERIES_ID,',
' --set if series is y or y2 axis',
' ''yAxis'' VALUE ''y'',',
' --type of the chart (bar,line,area,area-spline,bubble,donut,gauge,pie,radar,scatter,spline,step,area-step)',
' ''type'' VALUE CHART_TYPE,',
' --link when point of series is clicked',
' ''link'' VALUE ''https://linktr.ee/ronny.weiss'',',
' --color of series e.g #ff0000',
' ''color'' VALUE NULL,',
' --data for x axis',
' ''x'' VALUE X,',
' --data for y axis [num]',
' ''y'' VALUE Y * SERIES_ID,',
' --z dimension only needed when want a bubble chart with a dimension [num]',
' ''z'' VALUE NULL,',
' --custome tooltips',
' ''tooltip'' VALUE NULL',
'RETURNING BLOB) RETURNING BLOB)',
'FROM(SELECT ''Val '' || ROWNUM AS X, ROUND(DBMS_RANDOM.VALUE(1,100)) AS Y FROM DUAL CONNECT BY ROWNUM<=30)',
'JOIN ( SELECT ROWNUM AS SERIES_ID FROM DUAL CONNECT BY ROWNUM<=4) SERIES ON 1 = 1)',
'RETURNING BLOB ) AS JSON_BLOB FROM CT',
'</pre>'))
);
end;
