begin
wwv_flow_imp_shared.create_search_config(
 p_id=>wwv_flow_imp.id(63158935500611533)
,p_label=>'Socios_Acreditar'
,p_static_id=>'socios_acreditar'
,p_search_type=>'SIMPLE'
,p_location=>'LOCAL'
,p_query_type=>'SQL'
,p_query_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    S.SOCIO_ID,',
'    S.CEDULA,',
'    S.NROSOCIO,',
'    S.APELLIDOSNOMBRES,',
'    S.SITUACION,',
'    CASE ',
'        WHEN A.SOCIO_ID IS NOT NULL THEN ''ACREDITADO''',
'        ELSE ''PENDIENTE''',
'    END AS ESTADO,',
'    CASE ',
'        WHEN A.SOCIO_ID IS NOT NULL THEN ''fa-check-circle''',
'        ELSE ''fa-chevron-right''',
'    END AS ESTADO_ICON',
'FROM mivoto_socio S',
'LEFT JOIN mivoto_acreditacion A ON S.SOCIO_ID = A.SOCIO_ID;'))
,p_searchable_columns=>'CEDULA:NROSOCIO:APELLIDOSNOMBRES'
,p_pk_column_name=>'SOCIO_ID'
,p_title_column_name=>'APELLIDOSNOMBRES'
,p_description_column_name=>'SITUACION'
,p_link_target_type=>'REDIRECT_PAGE'
,p_link_target=>'f?p=&APP_ID.:21:&APP_SESSION.::&DEBUG.:21:P21_SOCIO_ID,P21_CEDULA,P21_APELLIDOSNOMBRES:&SOCIO_ID.,&CEDULA.,&APELLIDOSNOMBRES.'
,p_default_row_html_expr=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<div class="acred-card card-status-&ESTADO." data-id="&SOCIO_ID." data-estado="&ESTADO.">',
