prompt --application/shared_components/navigation/search_config/socios_consulta
begin
wwv_flow_imp_shared.create_search_config(
 p_id=>wwv_flow_imp.id(64803232754470786)
,p_label=>'Socios_Consulta'
,p_static_id=>'socios_consulta'
,p_search_type=>'SIMPLE'
,p_location=>'LOCAL'
,p_query_type=>'SQL'
,p_query_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    s.Cedula as CEDULA,',
'    s.SOCIO_ID as SOCIO_ID,',
'    s.NROSOCIO as SOCIO_NRO,',
'    ',
'    -- 1. Extraer Apellido1 + *****',
'    SUBSTR(s.ApellidosNombres, 1, INSTR(s.ApellidosNombres, '' '') - 1) || '' *****, '' ||',
'    ',
unistr('    -- 2. Extraer Nombre1 (lo que est\00E1 despu\00E9s de la coma y antes del siguiente espacio)'),
'    SUBSTR(',
'        s.ApellidosNombres, ',
unistr('        INSTR(s.ApellidosNombres, '','') + 2, -- Inicio despu\00E9s de la coma y el espacio'),
'        CASE ',
'            WHEN INSTR(s.ApellidosNombres, '' '', INSTR(s.ApellidosNombres, '','') + 2) = 0 ',
'            THEN LENGTH(s.ApellidosNombres) -- Si no hay segundo nombre, toma hasta el final',
'            ELSE INSTR(s.ApellidosNombres, '' '', INSTR(s.ApellidosNombres, '','') + 2) - (INSTR(s.ApellidosNombres, '','') + 2)',
'        END',
'    ) || '' *****'' as APELLIDOS_Y_NOMBRES,',
'    ',
'    s.Situacion as CONDICION,',
'    ',
'    CASE ',
'        WHEN s.Situacion = ''VOZ Y VOTO'' THEN ''badge-voto-si''',
'        ELSE ''badge-voto-no''',
'    END as CLASE_ESTADO,',
'    ',
'    CASE ',
'        WHEN s.Situacion = ''VOZ'' THEN',
'            (SELECT ',
'                NVL(RTRIM(',
'                    CASE WHEN NVL(e.MoraCC, 0) > 0 THEN ''Mora Aporte Ordinario, '' ELSE '''' END ||',
'                    CASE WHEN NVL(e.MoraSOL, 0) > 0 THEN ''Mora Solidaridad, '' ELSE '''' END ||',
unistr('                    CASE WHEN NVL(e.MoraAPE, 0) > 0 THEN ''Mora Fondo de Inversi\00F3n, '' ELSE '''' END ||'),
unistr('                    CASE WHEN NVL(e.MoraCREDITO, 0) > 0 THEN ''Mora Cr\00E9dito, '' ELSE '''' END ||'),
'                    CASE WHEN NVL(e.MoraCABAL, 0) > 0 THEN ''Mora Cabal, '' ELSE '''' END ||',
'                    CASE WHEN NVL(e.MoraVISA, 0) > 0 THEN ''Mora Visa'' ELSE '''' END,',
'                    '', ''), ''Sin detalles de mora registrados'')',
'             FROM mivoto_Estado e ',
'             WHERE e.Socio_id = s.Socio_id)',
'        ELSE ''HABILITADO PARA VOTAR''',
'    END as DETALLE_MORA',
'FROM mivoto_Socio s',
'WHERE s.Cedula LIKE ''%''||:P12_BUSQUEDA ||''%'' OR s.NROSOCIO LIKE ''%''||:P12_BUSQUEDA ||''%'' ;',
'',
''))
,p_searchable_columns=>'CEDULA:SOCIO_NRO'
,p_pk_column_name=>'SOCIO_ID'
,p_title_column_name=>'APELLIDOS_Y_NOMBRES'
,p_description_column_name=>'CONDICION'
,p_icon_source_type=>'INITIALS'
,p_default_row_html_expr=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<div class="acred-card card-status-&CONDICION." ">',
'    <div class="acred-card-body">',
'        <div class="acred-user-info">',
'            <h3 class="acred-name">&APELLIDOS_Y_NOMBRES.</h3>',
'',
'',
'            <div class="acred-meta">',
unistr('                <p class="acred-detail"><strong>C\00E9dula:</strong> &CEDULA.</p>'),
'            </div>',
'        </div>',
'        <div class="acred-badge-container">',
'            <span class="acred-badge status-&CONDICION.">&CONDICION.</span>',
'        </div>',
'            <div class="acred-badge-container">',
'            <span class="acred-badge status-&CONDICION.">&DETALLE_MORA.</span>',
'        </div>',
'    </div>',
'',
'    </div>',
'</div>'))
,p_version_scn=>45280467346487
);
end;
