wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(64344632108014520)
,p_process_sequence=>60
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'CREAR_USUARIO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'USUCOD NUMBER;',
'',
'BEGIN',
'',
'    SELECT COUNT(USUARIO_COD) INTO USUCOD',
'    FROM MIVOTO_USUARIO',
'    WHERE USUARIO_COD = :P5_USUARIO_COD;',
'',
'    IF (USUCOD = 0) THEN',
'',
'        INSERT INTO MIVOTO_USUARIO(',
'            NOMBRE,',
'            USUARIO_COD,',
'            PASSWORD,',
'            PASSWORDVENC,',
'            ROLE_ID',
'        )VALUES(',
'            :P5_NOMBRE,',
'            :P5_USUARIO_COD,',
'            FN_ENCRIPTAR_PASSWORD(:P5_PASSWORD),',
'            ADD_MONTHS(SYSDATE, 3),',
'            :P5_ROLE_ID',
'              ',
'        );',
'',
'    ELSE',
'       RAISE_APPLICATION_ERROR(-20001, ''Ya existe un "USUARIO_COD" igual, favor verificar.'');',
'',
'    END IF;',
'',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>64344632108014520
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(64344759420014521)
,p_process_sequence=>70
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'ACTUALIZAR_USUARIO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'USUCOD NUMBER;',
'',
'BEGIN',
'',
'    UPDATE MIVOTO_USUARIO SET',
'        NOMBRE = :P5_NOMBRE,',
'        USUARIO_COD = :P5_USUARIO_COD,',
'        PASSWORD = FN_ENCRIPTAR_PASSWORD(:P5_PASSWORD),',
'        PASSWORDVENC = ADD_MONTHS(SYSDATE, 3),',
'        ROLE_ID = :P5_ROLE_ID',
'    WHERE USUARIO_ID = :P5_USUARIO_ID;',
'',
'',
'END;'))
