'    color: #4CAF50;',
'    width: 70px;',
'    height: 70px;',
'    border-radius: 50%;',
'    display: flex;',
'    justify-content: center;',
'    align-items: center;',
'    font-size: 32px;',
'    margin: 0 auto 20px;',
'}',
'',
'.row{',
'    display: flex;',
'    flex-direction: column;',
'    /* margin: 0 auto; */',
'    /* flex-wrap: wrap; */',
'    justify-content: center;',
'    align-items: center;',
'}',
'',
'.acred-title h1{ ',
'    font-size: 20px; ',
'    font-weight: 600; ',
'    color: #1a1a1a; ',
'    margin-bottom: 10px; ',
'    }',
'.acred-title h3{ ',
'    font-size: 10px; ',
'    font-weight: 600; ',
'    color: #1a1a1a; ',
'    margin-bottom: 10px; ',
'    }',
'',
'.acred-description { ',
'    color: #757575; ',
'    font-size: 15px; ',
'    margin-bottom: 30px; ',
'    }',
'',
'/* ==========================================',
unistr('   2. BARRA DE B\00DASQUEDA (Inputs y Botones)'),
'   ========================================== */',
'.acred-search-bar {',
'    display: flex;',
'    gap: 10px;',
'    justify-content: center;',
'    align-items: flex-end;',
'}',
'',
'.acred-btn-apex {',
'    height: 44px !important;',
'    background-color: #8ccf9f !important;',
'    border-color: #8ccf9f !important;',
'    border-radius: 8px !important;',
'    color: white !important;',
'    font-weight: 600 !important;',
'    padding: 0 30px !important;',
'}',
'',
'.acred-btn-apex:hover { ',
'    background-color: #7bbd8e !important; ',
'}',
'',
