'    height: 44px !important;',
'    border-radius: 8px !important;',
'    width: 450px !important;',
'}',
'',
'.t-Form-fieldContainer.t-Form-fieldContainer--floatingLabel{',
'    width: 300px;',
'    margin: 0 auto;',
'',
'}',
'',
'/* ==========================================',
unistr('   3. RESULTADOS Y TARJETAS (Cards - Tama\00F1o Grande)'),
