'    color: #999;',
'    display: flex;',
'    justify-content: space-between;',
'    align-items: center;',
'}',
'',
'.acred-card-footer .fa { font-size: 18px !important; }',
'',
'/* ==========================================',
unistr('   4. DISTINTIVOS DE SITUACI\00D3N (Badges)'),
