'.acred-badge {',
'    display: inline-block;',
'    padding: 6px 20px !important;',
'    border-radius: 18px;',
'    font-size: 14px !important;',
'    font-weight: bold;',
'    margin-top: 15px !important;',
'    text-transform: uppercase;',
'}',
'',
'/* Caso: VOZ (Rojo) */',
'.status-VOZ { ',
'    background-color: #ffebee !important; ',
'    color: #d32f2f !important;           ',
