'    align-items: center;',
'    gap: 4px;',
'}',
'',
'/* Badge de Estado Pendiente */',
'.acred-status-indicator.state-VOZ {',
'    background-color: #f5f5f5;',
'    color: #757575;',
'    padding: 2px 8px;',
'    border-radius: 12px;',
'    font-size: 0.75rem;',
'    border: 1px dashed #bdbdbd;',
'}',
'',
unistr('/* --- CAMBIOS EN LA CARD SEG\00DAN ACREDITACI\00D3N --- */'),
'',
unistr('/* Si ya est\00E1 acreditado, suavizamos la card para que resalten los pendientes */'),
'',
'.acred-card.card-status-VOZ {',
'    border-left: 5px solid #c92828; /* Franja verde lateral */',
'    background-color: #f9fdf9;',
'    opacity: 0.9;',
'}',
'',
'.acred-card.card-status-VOZ .acred-action-text {',
'    color: #c92828; ',
'    font-weight: bold;',
'}',
'',
'.acred-card.card-status-VOZ .fa-check-circle {',
'    color: #c92828;',
'    font-size: 1.2rem;',
'}',
'',
'/* Caso: VOZ Y VOTO (Verde) */',
'.acred-card[class*="status-VOZ"][class*="VOTO"] { ',
'    border-left: 5px solid #2e7d32; /* Franja verde lateral */',
'    background-color: #f9fdf9;',
'    opacity: 0.9;      ',
'}',
'',
'.acred-card[class*="status-VOZ"][class*="VOTO"].acred-action-text {',
'    color: #2e7d32; ',
'    font-weight: bold;',
'}',
'',
'.acred-card[class*="status-VOZ"][class*="VOTO"].fa-check-circle {',
'    color: #2e7d32;',
'    font-size: 1.2rem;',
'}',
'',
'',
'',
unistr('/* Animaci\00F3n sutil al pasar el mouse por una card pendiente */'),
'.acred-card[class*="status-VOZ"][class*="VOTO"]:hover {',
'    border-left: 5px solid #6e7275;',
'    transform: translateY(-2px);',
'    transition: all 0.2s ease;',
'    border-color: #2e7d32;',
'}',
'.acred-card.card-status-VOZ:hover {',
'    border-left: 5px solid #6e7275;',
'    transform: translateY(-2px);',
'    transition: all 0.2s ease;',
'    border-color: #c92828;',
'}',
'',
'',
'/* ==========================================',
'   6. EN CASO DE NO ENCONTRAR ',
