'var socioId = $(this.triggeringElement).attr(''data-id'');',
'',
'if (!socioId) {',
unistr('    console.error("No se encontr\00F3 el ID del socio en la tarjeta.");'),
'    return;',
'}',
'',
'// Llamada AJAX al proceso que creamos en el Paso 1',
'apex.server.process(',
'    "GET_MODAL_URL",',
'    { x01: socioId }, ',
'    {',
'        success: function(pData) {',
'            if (pData.success && pData.url) {',
'                // Abrimos el modal con la URL firmada por el servidor',
'                apex.navigation.dialog(pData.url, {',
unistr('                    title: "Acreditaci\00F3n de Socio",'),
'                    height: "auto",',
'                    width: "800",',
'                    modal: true',
'                });',
'            } else {',
'                apex.message.alert("Error: " + pData.message);',
'            }',
'        },',
'        error: function() {',
unistr('            apex.message.alert("Error de comunicaci\00F3n con el servidor.");'),
'        }',
'    }',
');'))
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(63287011215603627)
,p_process_sequence=>10
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'GET_MODAL_URL'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_socio_id NUMBER := apex_application.g_x01;',
'    l_url      VARCHAR2(4000);',
'BEGIN',
'    -- Generamos la URL para la P21 con el ID del socio seleccionado',
'    l_url := APEX_PAGE.GET_URL(',
'                p_page   => 21,',
'                p_items  => ''P21_SOCIO_ID'',',
'                p_values => l_socio_id,',
'                p_clear_cache => ''21''',
'             );',
'',
'    APEX_JSON.OPEN_OBJECT;',
'    APEX_JSON.WRITE(''success'', TRUE);',
'    APEX_JSON.WRITE(''url'', l_url);',
'    APEX_JSON.CLOSE_OBJECT;',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        APEX_JSON.OPEN_OBJECT;',
'        APEX_JSON.WRITE(''success'', FALSE);',
'        APEX_JSON.WRITE(''message'', SQLERRM);',
'        APEX_JSON.CLOSE_OBJECT;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>63287011215603627
);
end;
