wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(59660357333767249)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'ACREDITAR'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE ',
'V_COUNT NUMBER; ',
'v_seq_ACREDITACION NUMBER;',
'BEGIN ',
'    v_seq_ACREDITACION := MIVOTO_ACREDITACION_SEQ.NEXTVAL;',
'',
'    SELECT count(1) INTO V_COUNT ',
'    FROM MIVOTO_ACREDITACION ',
'    WHERE SOCIO_ID = :P21_SOCIO_ID; ',
'',
'',
'    IF (V_COUNT = 0) THEN ',
'        INSERT INTO MIVOTO_ACREDITACION( ACREDITACION_ID, SOCIO_ID, SITUACION) ',
'        VALUES( v_seq_ACREDITACION, :P21_SOCIO_ID, :P21_SITUACION);',
'',
'        INSERT INTO MIVOTO_IMPRESIONES(ACREDITACION_ID, DESCRIPCION, IMPRESION)',
'        VALUES(v_seq_ACREDITACION, ''IMPRESION ORIGINAL'', 1) ;',
'',
'    ELSE ',
unistr('        RAISE_APPLICATION_ERROR(-20000, ''Socio ya fue acr\00E9ditado !''); '),
'',
'    END IF; ',
'',
'END;',
'',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'ACREDITAR'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_process_success_message=>'Socio acreditado correctamente !!'
,p_internal_uid=>59660357333767249
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(63209100754656116)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'REIMPRIMIR'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE ',
'V_COUNT NUMBER; ',
'V_ACREDITADO NUMBER; ',
'BEGIN ',
'    SELECT ACREDITACION_ID INTO V_ACREDITADO ',
'    FROM MIVOTO_ACREDITACION ',
'    WHERE SOCIO_ID = :P21_SOCIO_ID; ',
'',
'    SELECT COUNT(IMPRESIONE_ID) INTO V_COUNT',
'    FROM MIVOTO_IMPRESIONES',
'    WHERE ACREDITACION_ID = V_ACREDITADO;',
'',
'    INSERT INTO MIVOTO_IMPRESIONES(ACREDITACION_ID,',
'                                    DESCRIPCION,',
'                                    IMPRESION) ',
'    VALUES (',
'        V_ACREDITADO,',
'        ''REIMPRESO POR: ''|| :P21_USUARIO_COD || ''EN FECHA: ''|| :P21_FECHA || '' Y HORA: ''|| :P21_HORA,',
'        V_COUNT+1',
'    );',
'',
'END;',
'',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'REIMPRIMIR'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_process_success_message=>'Se ha reimpreso correctamente!!'
,p_internal_uid=>63209100754656116
);
