wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(64334031354987231)
,p_plug_name=>'DashBoard Acreditados'
,p_region_name=>'dashboard'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_escape_on_http_output=>'Y'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>10
,p_location=>null
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH DATA_BASE AS (',
unistr('    -- Unificamos socios con su estado de acreditaci\00F3n'),
'    SELECT ',
'        S.SITUACION,',
'        CASE WHEN A.SOCIO_ID IS NOT NULL THEN ''ACREDITADO'' ELSE ''PENDIENTE'' END AS ESTADO',
'    FROM MIVOTO_SOCIO S',
'    LEFT JOIN MIVOTO_ACREDITACION A ON S.SOCIO_ID = A.SOCIO_ID',
'/*',
'    --',
'    SELECT ',
'        SITUACION',
'    FROM MIVOTO_SOCIO ',
' */',
'),',
'',
'CHART_CONFIG AS (',
'    -- Definimos los dos Donuts',
unistr('    SELECT 1 AS ID, ''Estado de Acreditaci\00F3n'' AS TITLE, 6 AS SPAN FROM DUAL'),
'    UNION ALL',
unistr('    SELECT 2 AS ID, ''Derecho a Voto (Situaci\00F3n)'' AS TITLE, 6 AS SPAN FROM DUAL'),
')',
'SELECT',
'  JSON_OBJECT (',
'    ''title'' VALUE TITLE,',
'    ''colSpan'' VALUE SPAN,',
'    ''height'' VALUE 400,',
'    ''itemConfig'' VALUE JSON_OBJECT(',
'       ''legendShow'' VALUE 1,',
'       ''legendPosition'' VALUE ''bottom'',',
'       ''xType'' VALUE ''category'',',
'       ''showDataLabels'' VALUE 1,',
'       ''donutTitle'' VALUE TITLE ',
'    RETURNING BLOB),',
'    ''itemData'' VALUE (',
'        CASE ',
'          WHEN ID = 1 THEN (',
'                -- Donut 1: Concatenamos el Estado con la Cantidad',
'                SELECT JSON_ARRAYAGG(JSON_OBJECT(',
'                    ''seriesID'' VALUE ESTADO,',
'                    ''label'' VALUE ESTADO || '' ('' || COUNT(*) || '')'', -- Muestra: ACREDITADO (250)',
'                    ''type'' VALUE ''donut'',',
'                    ''color'' VALUE CASE WHEN ESTADO = ''ACREDITADO'' THEN ''#005d18'' ELSE ''#808080'' END,',
'                    ''x'' VALUE ESTADO,',
'                    ''y'' VALUE COUNT(*)',
'                RETURNING BLOB) RETURNING BLOB)',
'                FROM DATA_BASE GROUP BY ESTADO',
'            )',
'            WHEN ID = 2 THEN (',
unistr('                -- Donut 2: Concatenamos la Situaci\00F3n con la Cantidad'),
'                SELECT JSON_ARRAYAGG(JSON_OBJECT(',
'                    ''seriesID'' VALUE SITUACION,',
'                    ''label'' VALUE SITUACION || '' ('' || COUNT(1) || '')'', -- Muestra: VOZ Y VOTO (180)',
'                    ''type'' VALUE ''donut'',',
'                    ''color'' VALUE CASE ',
'                                    WHEN SITUACION LIKE ''%VOTO%'' THEN ''#005d18'' ',
'                                    ELSE ''#808080'' ',
'                                 END,',
'                    ''x'' VALUE SITUACION,',
'                    ''y'' VALUE COUNT(1)',
'                RETURNING BLOB) RETURNING BLOB)',
'                FROM DATA_BASE GROUP BY SITUACION',
'            )',
'        END',
'    )',
'  RETURNING BLOB ) AS JSON_BLOB',
'FROM CHART_CONFIG;'))
,p_plug_source_type=>'PLUGIN_APEX.D3.DASHBOARD.CHARTS'
,p_plug_required_role=>wwv_flow_imp.id(64724729136932979)
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
