wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(64344315097014517)
,p_plug_name=>'Acreditados por Sucursal'
,p_region_name=>'dashboard2'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_escape_on_http_output=>'Y'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>50
,p_location=>null
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH DATA_BASE AS (',
'    SELECT ',
'        S.AGENCIA,',
'        CASE WHEN A.SOCIO_ID IS NOT NULL THEN ''ACREDITADO'' ELSE ''PENDIENTE'' END AS ESTADO',
'    FROM MIVOTO_SOCIO S',
'    LEFT JOIN MIVOTO_ACREDITACION A ON S.SOCIO_ID = A.SOCIO_ID',
'    WHERE S.SOCIO_ID BETWEEN 1 AND 50000',
'),',
'AGENCIAS_COLORES AS (',
'    -- Generamos un color usando ORA_HASH para evitar errores de permisos',
'    SELECT ',
'        AGENCIA, ',
unistr('        -- Crea un color basado en el nombre de la agencia usando una operaci\00F3n matem\00E1tica simple'),
'        ''#'' || SUBSTR(TO_CHAR(ORA_HASH(AGENCIA, 16777215), ''FM000000X''), 1, 6) as COLOR_AGENCIA',
'    FROM (SELECT DISTINCT AGENCIA FROM DATA_BASE)',
')',
'SELECT',
'  JSON_OBJECT (',
unistr('    ''title'' VALUE ''Acreditaci\00F3n por Sucursal (Vista Spline)'','),
'    ''colSpan'' VALUE 12,',
'    ''height'' VALUE 500,',
'    ''itemConfig'' VALUE JSON_OBJECT(',
'       ''legendShow'' VALUE 1,',
'       ''legendPosition'' VALUE ''right'',',
'       ''xType'' VALUE ''category'',',
'       ''zoomEnabled'' VALUE 1,',
'       ''zoomType'' VALUE ''drag'',',
'       ''gridY'' VALUE 1',
'    RETURNING BLOB),',
'    ''itemData'' VALUE (',
'        SELECT JSON_ARRAYAGG(JSON_OBJECT(',
'            ''seriesID'' VALUE D.AGENCIA,',
'            ''label'' VALUE D.AGENCIA,',
'            ''type'' VALUE ''spline'',',
'            ''color'' VALUE C.COLOR_AGENCIA,',
'            ''x'' VALUE D.ESTADO,',
'            ''y'' VALUE COUNT(*)',
'        RETURNING BLOB) RETURNING BLOB)',
'        FROM DATA_BASE D',
'        JOIN AGENCIAS_COLORES C ON D.AGENCIA = C.AGENCIA',
'        GROUP BY D.AGENCIA, D.ESTADO, C.COLOR_AGENCIA',
'    )',
'  RETURNING BLOB ) AS JSON_BLOB',
'FROM DUAL;'))
