'WITH DATA_TIME AS (',
unistr('    -- Acreditaci\00F3n por minuto'),
'    SELECT ',
'        TO_CHAR(CREADO_EL, ''HH24:MI'') AS MINUTO,',
'        COUNT(*) AS CANTIDAD',
'    FROM MIVOTO_ACREDITACION',
unistr('    -- Filtramos solo el d\00EDa de hoy para que el gr\00E1fico no se sature'),
'    --WHERE CREADO_EL >= TRUNC(SYSDATE) ',
'    GROUP BY TO_CHAR(CREADO_EL, ''HH24:MI'')',
'    ORDER BY MINUTO',
')',
'SELECT',
'  JSON_OBJECT ( ',
unistr('  ''title'' VALUE ''Monitoreo de Acreditaci\00F3n por Minuto'','),
'  ''colSpan'' VALUE 12,',
'  ''height'' VALUE 450,',
'  ''itemConfig'' VALUE JSON_OBJECT(',
'       ''zoomType'' VALUE ''drag'',',
'       ''xLabel'' VALUE ''Tiempo (HH:MM)'',',
'       ''yLabel'' VALUE ''Socios Acreditados'',',
'       ''gridX'' VALUE 1,',
'       ''gridY'' VALUE 1,',
'       -- Mostramos menos etiquetas en el eje X para que no se amontonen los minutos',
'       ''tickMaxnum'' VALUE 20 ',
'   RETURNING BLOB),',
'  ''itemData'' VALUE (',
'      SELECT JSON_ARRAYAGG(JSON_OBJECT(',
'           ''seriesID'' VALUE ''AcreditadosMin'',',
'           ''label'' VALUE ''Acreditaciones/Min'',',
'           ''type'' VALUE ''area-spline'',',
'           ''color'' VALUE ''#00873e'', ',
'           ''x'' VALUE MINUTO,',
'           ''y'' VALUE CANTIDAD',
'      RETURNING BLOB) RETURNING BLOB)',
'      FROM DATA_TIME',
'  )',
'  RETURNING BLOB ) AS JSON_BLOB',
'FROM DUAL'))
,p_plug_source_type=>'PLUGIN_APEX.D3.DASHBOARD.CHARTS'
