'DECLARE',
'    V_PASS VARCHAR(200);',
'    V_PASS_COMPARE VARCHAR(200);',
'',
'BEGIN',
'    V_PASS_COMPARE := :P8000_PASSWORD_OLD;',
'',
'    SELECT PASSWORD INTO V_PASS',
'    FROM MIVOTO_USUARIO',
'    WHERE UPPER(USUARIO_COD) = UPPER(coalesce(sys_context(''APEX$SESSION'',''APP_USER''),user));',
'',
'',
'    IF(UPPER(V_PASS) = UPPER(FN_ENCRIPTAR_PASSWORD(V_PASS_COMPARE))) THEN',
'        RETURN TRUE;',
'    ELSE',
'        RETURN FALSE;',
'    END IF;',
'',
'END;'))
,p_validation2=>'PLSQL'
,p_validation_type=>'FUNC_BODY_RETURNING_BOOLEAN'
