'DECLARE ',
'    APP_USUARIO   VARCHAR2(15);',
'    PASS_NEW      VARCHAR2(100);',
'    USER_ID       NUMBER;',
'BEGIN',
'    APP_USUARIO := COALESCE(sys_context(''APEX$SESSION'',''APP_USER''), USER);',
'    PASS_NEW := :P8000_PASSWORD_NEW;',
'',
'    SELECT USUARIO_ID',
'    INTO USER_ID',
'    FROM MIVOTO_USUARIO',
'    WHERE USUARIO_COD = APP_USUARIO;',
'',
'    UPDATE MIVOTO_USUARIO',
'    SET PASSWORD = FN_ENCRIPTAR_PASSWORD(PASS_NEW),',
'        PASSWORDVENC = ADD_MONTHS(SYSDATE, 3)  -- suma 3 meses desde hoy',
'    WHERE USUARIO_ID = USER_ID;',
'',
'    COMMIT;',
'END;',
'',
''))
